"use client";

import { HTMLAttributes, forwardRef, useState } from "react";
import { cn, swirskiAttrs } from "../../system";
import { CursorPicker } from "./CursorPicker";
import { useSwirskiCursor } from "./CursorProvider";

export type CursorDockProps = {
  label?: string;
  position?: "fixed" | "absolute";
  side?: "left" | "right";
  variant?: "default";
  size?: "md";
  tone?: "default";
} & HTMLAttributes<HTMLDivElement>;

export const CursorDock = forwardRef<HTMLDivElement, CursorDockProps>(
  function CursorDock({
  className,
  label = "Choose cursor",
  position = "fixed",
  side = "right",
  variant = "default",
  size = "md",
  tone = "default",
  onBlur,
  onFocus,
  onMouseEnter,
  onMouseLeave,
  ...props
}, ref) {
  const { cursor } = useSwirskiCursor();
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div
      ref={ref}
      className={cn(
        "group top-1/2 z-50 hidden -translate-y-1/2 items-center gap-0 lg:flex",
        position === "fixed" ? "fixed" : "absolute",
        side === "right" ? "right-0 flex-row" : "left-0 flex-row-reverse",
        className,
      )}
      onBlur={(event) => {
        onBlur?.(event);

        if (!event.currentTarget.contains(event.relatedTarget)) {
          setIsOpen(false);
        }
      }}
      onFocus={(event) => {
        onFocus?.(event);
        setIsOpen(true);
      }}
      onMouseEnter={(event) => {
        onMouseEnter?.(event);
        setIsOpen(true);
      }}
      onMouseLeave={(event) => {
        onMouseLeave?.(event);
        setIsOpen(false);
      }}
      {...swirskiAttrs("cursor-dock", { size, tone, variant })}
      {...props}
    >
      <div
        aria-hidden={!isOpen}
        className={cn(
          "overflow-hidden transition-[max-width,opacity,transform] duration-200 ease-out",
          isOpen
            ? "max-w-[calc(100vw-5rem)] opacity-100"
            : "max-w-0 opacity-0",
          side === "right"
            ? isOpen
              ? "translate-x-0"
              : "translate-x-4"
            : isOpen
              ? "translate-x-0"
              : "-translate-x-4",
        )}
      >
        <CursorPicker
          className={cn(
            "mx-3 w-max max-w-[calc(100vw-6rem)]",
            !isOpen && "pointer-events-none",
          )}
          label={label}
          buttonTabIndex={isOpen ? undefined : -1}
          showLabels
        />
      </div>

      <button
        aria-expanded={isOpen}
        aria-label={label}
        className={cn(
          "grid size-14 place-items-center border-4 border-black bg-[#FFD400] shadow-[5px_5px_0_#0B0B0C] transition-all duration-150",
          "hover:translate-x-1 hover:translate-y-1 hover:shadow-none",
          "focus-visible:outline focus-visible:outline-4 focus-visible:outline-offset-2 focus-visible:outline-[#0057FF]",
          side === "right" ? "border-r-0" : "border-l-0",
        )}
        onClick={() => setIsOpen((open) => !open)}
        type="button"
        {...swirskiAttrs("cursor-dock-trigger", { size, tone, variant })}
      >
        <span
          aria-hidden="true"
          className="block size-8 bg-contain bg-center bg-no-repeat"
          style={{ backgroundImage: `url("${cursor.preview}")` }}
        />
      </button>
    </div>
  );
});

CursorDock.displayName = "CursorDock";

"use client";

import { HTMLAttributes, forwardRef } from "react";
import { cn, swirskiAttrs } from "../../system";
import { useSwirskiCursor } from "./CursorProvider";

export type CursorPickerProps = {
  buttonTabIndex?: number;
  label?: string;
  showLabels?: boolean;
  variant?: "default";
  size?: "md";
  tone?: "default";
} & HTMLAttributes<HTMLDivElement>;

export const CursorPicker = forwardRef<HTMLDivElement, CursorPickerProps>(
  function CursorPicker({
  buttonTabIndex,
  className,
  label = "Cursor",
  showLabels = true,
  variant = "default",
  size = "md",
  tone = "default",
  ...props
}, ref) {
  const { cursorId, cursors, setCursor } = useSwirskiCursor();

  return (
    <div
      ref={ref}
      aria-label={label}
      className={cn(
        "inline-flex flex-wrap gap-2 border-4 border-black bg-[#F5F5F3] p-2 shadow-[6px_6px_0_#0B0B0C]",
        className,
      )}
      role="radiogroup"
      {...swirskiAttrs("cursor-picker", { size, tone, variant })}
      {...props}
    >
      {cursors.map((cursor) => {
        const isSelected = cursor.id === cursorId;

        return (
          <button
            aria-checked={isSelected}
            aria-label={cursor.name}
            className={cn(
              "group relative flex min-h-14 min-w-14 items-center gap-2 border-4 border-black bg-white px-3 py-2 text-left transition-all duration-150",
              "hover:-translate-y-1 hover:shadow-[5px_5px_0_#0B0B0C]",
              "focus-visible:outline focus-visible:outline-4 focus-visible:outline-offset-2 focus-visible:outline-[#0057FF]",
              isSelected
                ? "translate-x-1 translate-y-1 shadow-none"
                : "shadow-[4px_4px_0_#0B0B0C]",
            )}
            key={cursor.id}
            onClick={() => setCursor(cursor.id)}
            role="radio"
            style={{ backgroundColor: isSelected ? cursor.swatch : undefined }}
            tabIndex={buttonTabIndex}
            title={cursor.description}
            type="button"
          >
            <span
              aria-hidden="true"
              className="block size-8 shrink-0 bg-contain bg-center bg-no-repeat"
              style={{ backgroundImage: `url("${cursor.preview}")` }}
            />

            {showLabels ? (
              <span
                className={cn(
                  "pr-1 font-black uppercase leading-none tracking-normal",
                  isSelected && cursor.id !== "bolt"
                    ? "text-white"
                    : "text-black",
                )}
              >
                {cursor.name}
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
});

CursorPicker.displayName = "CursorPicker";

"use client";

import {
  createContext,
  CSSProperties,
  HTMLAttributes,
  ReactNode,
  forwardRef,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
} from "react";
import { cn, swirskiAttrs } from "../../system";
import {
  getSwirskiCursor,
  swirskiCursors,
  CursorId,
  SwirskiCursor,
} from "./cursors";

type CursorContextValue = {
  cursor: SwirskiCursor;
  cursorId: CursorId;
  cursors: SwirskiCursor[];
  setCursor: (cursorId: CursorId) => void;
};

const CursorContext = createContext<CursorContextValue | null>(null);

export type CursorProviderProps = {
  children: ReactNode;
  cursors?: SwirskiCursor[];
  cursor?: CursorId;
  defaultCursor?: CursorId;
  onCursorChange?: (cursorId: CursorId) => void;
  storageKey?: string | false;
  variant?: "default";
  size?: "md";
  tone?: "default";
} & HTMLAttributes<HTMLDivElement>;

const cursorSelectorStyles = `
@media (min-width: 1024px) and (hover: hover) and (pointer: fine) {
  [data-swirski-cursor] {
    cursor: var(--swirski-cursor);
  }

  [data-swirski-cursor] :is(
    a,
    button,
    summary,
    label,
    select,
    input[type="button"],
    input[type="checkbox"],
    input[type="radio"],
    input[type="reset"],
    input[type="submit"],
    [role="button"],
    [data-cursor="pointer"]
  ) {
    cursor: var(--swirski-cursor-pointer);
  }

  [data-swirski-cursor] :is(
    a,
    button,
    summary,
    label,
    select,
    input[type="button"],
    input[type="checkbox"],
    input[type="radio"],
    input[type="reset"],
    input[type="submit"],
    [role="button"],
    [data-cursor="pointer"],
    [data-cursor="active"]
  ):active {
    cursor: var(--swirski-cursor-active);
  }

  [data-swirski-cursor][data-swirski-cursor-pressed="true"],
  [data-swirski-cursor][data-swirski-cursor-pressed="true"] * {
    cursor: var(--swirski-cursor-active);
  }

  [data-swirski-cursor] :is(
    input:not([type="button"]):not([type="checkbox"]):not([type="radio"]):not([type="reset"]):not([type="submit"]),
    textarea,
    [contenteditable="true"]
  ) {
    cursor: text;
  }
}
`;

function getStoredCursor(
  storageKey: string | false,
  cursors: SwirskiCursor[],
): CursorId | null {
  if (storageKey === false || typeof window === "undefined") {
    return null;
  }

  try {
    const storedCursor = window.localStorage.getItem(storageKey);

    if (!storedCursor) {
      return null;
    }

    const exists = cursors.some((cursor) => cursor.id === storedCursor);

    return exists ? (storedCursor as CursorId) : null;
  } catch {
    return null;
  }
}

function storeCursor(storageKey: string | false, cursorId: CursorId) {
  if (storageKey === false || typeof window === "undefined") {
    return;
  }

  try {
    window.localStorage.setItem(storageKey, cursorId);
  } catch {
    // Ignore storage errors, for example private browsing or blocked storage.
  }
}

function findCursor(cursors: SwirskiCursor[], cursorId: CursorId) {
  return (
    cursors.find((cursor) => cursor.id === cursorId) ??
    getSwirskiCursor(cursorId) ??
    cursors[0] ??
    swirskiCursors[0]
  );
}

export const CursorProvider = forwardRef<HTMLDivElement, CursorProviderProps>(
  function CursorProvider({
  children,
  className,
  cursors = swirskiCursors,
  cursor,
  defaultCursor = "bolt",
  onCursorChange,
  storageKey = "swirski-cursor",
  variant = "default",
  size = "md",
  tone = "default",
  onPointerDownCapture,
  style,
  ...props
}, ref) {
  const isControlled = cursor !== undefined;

  const [selectedCursor, setSelectedCursor] = useState<CursorId>(() => {
    return defaultCursor;
  });

  const [isPressed, setIsPressed] = useState(false);

  useEffect(() => {
    if (isControlled) {
      return;
    }

    const storedCursor = getStoredCursor(storageKey, cursors);

    if (storedCursor) {
      setSelectedCursor(storedCursor);
    }
  }, [cursors, isControlled, storageKey]);

  useEffect(() => {
    if (!isPressed || typeof window === "undefined") {
      return;
    }

    const releaseCursor = () => {
      setIsPressed(false);
    };

    window.addEventListener("pointerup", releaseCursor);
    window.addEventListener("pointercancel", releaseCursor);
    window.addEventListener("blur", releaseCursor);
    window.addEventListener("contextmenu", releaseCursor);

    return () => {
      window.removeEventListener("pointerup", releaseCursor);
      window.removeEventListener("pointercancel", releaseCursor);
      window.removeEventListener("blur", releaseCursor);
      window.removeEventListener("contextmenu", releaseCursor);
    };
  }, [isPressed]);

  const cursorId = cursor ?? selectedCursor;

  const activeCursor = useMemo(() => {
    return findCursor(cursors, cursorId);
  }, [cursors, cursorId]);

  const setCursor = useCallback(
    (nextCursor: CursorId) => {
      const cursorExists = cursors.some((cursor) => cursor.id === nextCursor);

      if (!cursorExists) {
        return;
      }

      if (!isControlled) {
        setSelectedCursor(nextCursor);
      }

      storeCursor(storageKey, nextCursor);
      onCursorChange?.(nextCursor);
    },
    [cursors, isControlled, onCursorChange, storageKey],
  );

  const value = useMemo<CursorContextValue>(
    () => ({
      cursor: activeCursor,
      cursorId: activeCursor.id,
      cursors,
      setCursor,
    }),
    [activeCursor, cursors, setCursor],
  );

  const cursorStyle = {
    "--swirski-cursor": activeCursor.cursor,
    "--swirski-cursor-pointer": activeCursor.pointer,
    "--swirski-cursor-active": activeCursor.active,
  } as CSSProperties;

  return (
    <CursorContext.Provider value={value}>
      <style>{cursorSelectorStyles}</style>

      <div
        ref={ref}
        className={cn("min-h-full", className)}
        data-swirski-cursor={activeCursor.id}
        data-swirski-cursor-pressed={isPressed ? "true" : undefined}
        {...swirskiAttrs("cursor-provider", { size, tone, variant })}
        style={{ ...cursorStyle, ...style }}
        onPointerDownCapture={(event) => {
          onPointerDownCapture?.(event);

          if (event.pointerType === "mouse") {
            setIsPressed(true);
          }
        }}
        {...props}
      >
        {children}
      </div>
    </CursorContext.Provider>
  );
});

CursorProvider.displayName = "CursorProvider";

export function useSwirskiCursor() {
  const context = useContext(CursorContext);

  if (!context) {
    throw new Error("useSwirskiCursor must be used inside CursorProvider.");
  }

  return context;
}

export type SwirskiCursorId = "bolt" | "sticker" | "brush" | "target";
export type CursorId = SwirskiCursorId | (string & {});

export type SwirskiCursor = {
  id: CursorId;
  name: string;
  description: string;
  active: string;
  cursor: string;
  pointer: string;
  preview: string;
  swatch: string;
};

function toDataUri(svg: string) {
  return `data:image/svg+xml,${encodeURIComponent(svg)
    .replace(/'/g, "%27")
    .replace(/"/g, "%22")}`;
}

function cursorValue(
  svg: string,
  hotspotX: number,
  hotspotY: number,
  fallback: "auto" | "pointer",
) {
  return `url("${toDataUri(svg)}") ${hotspotX} ${hotspotY}, ${fallback}`;
}
function pixelArrow(fill: string, accent: string, shadow: string) {
  return `<svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 32 32" shape-rendering="crispEdges">
  <!-- offset comic shadow -->
  <path d="M9 5h4v3h3v3h3v3h3v3h3v4h-8v3h3v5h-6v-5h-3l-3 5H8v-8H5V5z" fill="${shadow}"/>

  <!-- black chunky outline -->
  <path d="M5 1h5v3h3v3h3v3h3v3h3v3h4v7h-8v2h3v7h-8v-6h-2l-3 6H3v-8H1V1z" fill="#0B0B0C"/>

  <!-- main fill -->
  <path d="M6 4h3v3h3v3h3v3h3v3h4v3h-8v4h3v5h-2v-6h-5l-3 6H6v-8H4V4z" fill="${fill}"/>

  <!-- pop-art inner cut -->
  <path d="M9 7h2v3h3v3h3v2h-5v3H9z" fill="${accent}"/>

  <!-- stitch / halftone marks -->
  <path d="M7 6h1v1H7zM10 10h1v1h-1zM13 13h1v1h-1zM16 16h1v1h-1z" fill="#0B0B0C"/>
</svg>`;
}

function pixelHand(fill: string, accent: string, shadow: string) {
  return `<svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 32 32" shape-rendering="crispEdges">
  <!-- offset comic shadow -->
  <path d="M16 5h5v4h3v3h3v15h-2v4H12v-3H9v-4H7v-4H5v-6h5v2h2V5z" fill="${shadow}"/>

  <!-- black outline -->
  <path d="M12 1h7v4h3v3h3v3h3v16h-2v4H10v-3H7v-4H5v-4H3v-8h6v2h2V1z" fill="#0B0B0C"/>

  <!-- hand fill -->
  <path d="M14 4h3v15h2V8h2v12h2v-9h2v13h-2v3H11v-3H9v-4H7v-5h2v2h5z" fill="${fill}"/>

  <!-- graphic palm shadow / sticker fold -->
  <path d="M17 8h1v12h-3v-2h2zM21 10h1v10h-2V10zM24 13h1v10h-2V13zM10 18h4v2h-4z" fill="${accent}"/>

  <!-- Swirski stitch marks -->
  <path d="M12 23h1v1h-1zM14 24h1v1h-1zM16 23h1v1h-1zM18 24h1v1h-1z" fill="#0B0B0C"/>
</svg>`;
}

function pixelClickHand(fill: string, accent: string, shadow: string) {
  return `<svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 32 32" shape-rendering="crispEdges">
  <!-- action marks -->
  <path d="M4 4h3v2H4zM7 7h2v2H7zM23 3h2v4h-2zM26 7h3v2h-3z" fill="${accent}"/>

  <!-- offset comic shadow -->
  <path d="M15 9h5v2h4v3h3v13h-2v4H11v-3H8v-4H6v-4H4v-6h5v-2h4V9z" fill="${shadow}"/>

  <!-- black outline -->
  <path d="M12 5h7v2h4v3h3v3h2v13h-2v4H9v-3H6v-4H4v-4H2v-8h6V9h4z" fill="#0B0B0C"/>

  <!-- compressed hand fill -->
  <path d="M14 8h3v3h4v3h3v1h2v9h-2v3H10v-3H8v-4H6v-5h2v3h6z" fill="${fill}"/>

  <!-- pressed highlight -->
  <path d="M17 11h4v3h2v2h-7zM22 16h2v8h-2zM9 16h5v2H9z" fill="${accent}"/>

  <!-- tiny halftone/stitch dots -->
  <path d="M12 22h1v1h-1zM14 23h1v1h-1zM16 22h1v1h-1zM18 23h1v1h-1z" fill="#0B0B0C"/>
</svg>`;
}

function pixelCursorSet(fill: string, accent: string, shadow: string) {
  const cursor = pixelArrow(fill, accent, shadow);
  const pointer = pixelHand(fill, accent, shadow);
  const active = pixelClickHand(fill, accent, shadow);

  return {
    active: cursorValue(active, 14, 10, "pointer"),
    cursor: cursorValue(cursor, 5, 2, "auto"),
    pointer: cursorValue(pointer, 15, 3, "pointer"),
    preview: toDataUri(cursor),

  };
}

const studioClassic = pixelCursorSet("#FFFFFF", "#F5F5F3", "#00D7DF");
const bangYellow = pixelCursorSet("#FFD400", "#FFFFFF", "#0057FF");
const comicPink = pixelCursorSet("#FF4FD8", "#FFD400", "#0057FF");
const stitchGreen = pixelCursorSet("#00D084", "#FFFFFF", "#FF4FD8");

export const swirskiCursors: SwirskiCursor[] = [
  {
    id: "bolt",
    name: "Studio Classic",
    description: "White sticker cursor with a cyan comic shadow.",
    ...studioClassic,
    swatch: "#00D7DF",
  },
  {
    id: "sticker",
    name: "Bang Yellow",
    description: "Yellow pop-art cursor with a bold blue offset shadow.",
    ...bangYellow,
    swatch: "#FFD400",
  },
  {
    id: "brush",
    name: "Comic Pink",
    description: "Hot pink cursor set with yellow highlights and blue shadow.",
    ...comicPink,
    swatch: "#FF4FD8",
  },
  {
    id: "target",
    name: "Stitch Green",
    description: "Green cursor set with a pink stitched comic shadow.",
    ...stitchGreen,
    swatch: "#00D084",
  },
];

export function getSwirskiCursor(id: CursorId) {
  return swirskiCursors.find((cursor) => cursor.id === id) ?? swirskiCursors[0];
}

export { CursorDock } from "./CursorDock";
export { CursorPicker } from "./CursorPicker";
export { CursorProvider, useSwirskiCursor } from "./CursorProvider";
export { getSwirskiCursor, swirskiCursors } from "./cursors";
export type { CursorDockProps } from "./CursorDock";
export type { CursorPickerProps } from "./CursorPicker";
export type { CursorProviderProps } from "./CursorProvider";
export type { CursorId, SwirskiCursor, SwirskiCursorId } from "./cursors";
